import { Icons } from "@repo/ui/components/icons";
import {
  Activity,
  ArrowUp,
  Briefcase,
  ChevronsUpDown,
  HelpCircle,
  MessageSquare,
  Plug,
  Search,
  Settings,
} from "lucide-react";
import { ProductDemoMailbox } from "./product-demo-mailbox";

export function ProductDemo() {
  return (
    <div className="dark overflow-hidden rounded-xl">
      <div className="flex h-[540px] bg-sidebar md:h-[580px] lg:h-[620px]">
        {/* Sidebar — hidden below lg */}
        <Sidebar />
        {/* Right column */}
        <div className="flex min-h-0 flex-1 flex-col pr-1.5 pb-1.5 md:pr-2 md:pb-2">
          {/* Inset card */}
          <div className="mt-1.5 flex flex-1 overflow-hidden rounded-xl bg-background md:mt-2">
            <ProductDemoMailbox />
            <Chat />
          </div>
        </div>
      </div>
    </div>
  );
}

/* ------------------------------------------------------------------ */
/*  Sidebar                                                           */
/* ------------------------------------------------------------------ */

const sidebarPrimaryNav = [
  { label: "Explore", icon: MessageSquare, active: true },
];

const sidebarManageNav = [
  { label: "Events", icon: Activity },
  { label: "Sources", icon: Plug },
  { label: "Jobs", icon: Briefcase },
  { label: "Settings", icon: Settings },
];

function Sidebar() {
  return (
    <div className="hidden w-[14rem] shrink-0 flex-col lg:flex">
      {/* Header */}
      <div className="flex h-14 items-center gap-2 px-4">
        <Icons.logoShort className="size-3" />
        <span className="font-medium text-base">Lightfast</span>
        <ChevronsUpDown className="ml-auto size-3.5 opacity-50" />
        <button
          className="flex size-6 items-center justify-center rounded-full text-muted-foreground hover:bg-muted"
          type="button"
        >
          <Search className="size-3.5" />
        </button>
      </div>

      {/* Primary nav */}
      <div className="flex flex-col gap-0.5 px-2">
        {sidebarPrimaryNav.map((item) => (
          <div
            className={`flex items-center gap-2 rounded-xl px-2 py-1.5 text-sm ${
              item.active ? "text-foreground" : "text-muted-foreground"
            }`}
            key={item.label}
          >
            <item.icon className="size-3.5" />
            <span>{item.label}</span>
          </div>
        ))}
      </div>

      {/* Manage group */}
      <div className="mt-4 flex flex-col gap-0.5">
        <span className="px-4 text-muted-foreground text-xs">Manage</span>
        <div className="flex flex-col gap-0.5 px-2">
          {sidebarManageNav.map((item) => (
            <div
              className="flex items-center gap-2 rounded-xl px-2 py-1.5 text-muted-foreground text-sm"
              key={item.label}
            >
              <item.icon className="size-3.5" />
              <span>{item.label}</span>
            </div>
          ))}
        </div>
      </div>

      {/* Footer */}
      <div className="mt-auto px-4 pb-4">
        <div className="flex size-8 items-center justify-center rounded-full bg-muted">
          <HelpCircle className="size-3.5" />
        </div>
      </div>
    </div>
  );
}

/* ------------------------------------------------------------------ */
/*  Chat (empty state)                                                */
/* ------------------------------------------------------------------ */

function Chat() {
  return (
    <div className="flex flex-1 flex-col items-center justify-center bg-background">
      <div className="-mt-24 w-full max-w-3xl px-6">
        <h2 className="text-center font-semibold text-3xl">
          Explore your infrastructure
        </h2>
        {/* Prompt input replica */}
        <div className="mt-4 w-full rounded-xl border border-border/50 bg-card/40 backdrop-blur-md">
          <div className="flex items-center justify-between p-3">
            <span className="text-muted-foreground text-sm">
              Ask anything about your organization...
            </span>
            <div className="flex size-8 items-center justify-center rounded-full border border-border/50">
              <ArrowUp className="size-4" />
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

