9	import { Easing, interpolate, useCurrentFrame } from "@vendor/remotion";
10	import type React from "react";
11	import { IsometricCard } from "../shared/isometric-card";
12	import { BEAM_TIMING } from "../shared/timing";
13	
14	// ── Search result items — 8 items × 19 frames = 152, spans [typingEndFrame, 299] ──
15	const RESULT_ITEMS = [
16	  {
17	    title: "Authentication service architecture decision",
18	    domain: "github.com/acme/backend",
19	    timestamp: "3 days ago",
20	  },
21	  {
22	    title: "API rate limiting implementation — PR #842",
23	    domain: "github.com/acme/api",
24	    timestamp: "1 week ago",
25	  },
26	  {
27	    title: "User authentication flow diagram",
28	    domain: "notion.so/acme/docs",
29	    timestamp: "2 weeks ago",
30	  },
31	  {
32	    title: "Choosing between Clerk vs Auth0",
33	    domain: "slack.com/acme/engineering",
34	    timestamp: "3 weeks ago",
35	  },
36	  {
37	    title: "Auth middleware refactor discussion",
38	    domain: "github.com/acme/backend",
39	    timestamp: "1 month ago",
40	  },
41	  {
42	    title: "JWT refresh token rotation implementation",
43	    domain: "github.com/acme/backend",
44	    timestamp: "1 week ago",
45	  },
46	  {
47	    title: "OAuth2 provider comparison notes",
48	    domain: "notion.so/acme/docs",
49	    timestamp: "2 weeks ago",
50	  },
51	  {
52	    title: "Session hijacking vulnerability report",
53	    domain: "slack.com/acme/security",
54	    timestamp: "3 weeks ago",
55	  },
56	];
57	
58	const PRIMARY_NAV = [
59	  { label: "Ask", active: true },
60	  { label: "Search", active: false },
61	];
62	
63	const MANAGE_NAV = [
64	  { label: "Sources", active: false },
65	  { label: "Jobs", active: false },
66	  { label: "Settings", active: false },
67	];
68	
69	const QUERY_TEXT = '"How does our authentication service work?"';
70	const SIDEBAR_WIDTH = 256;
71	const ROW_HEIGHT = 62;
72	
73	const N = RESULT_ITEMS.length;
74	// 8 items × 19 frames = 152 — exactly spans the [typingEndFrame (148), 299] cycling window
75	const FRAMES_PER_ITEM = 19;
76	const LOOP_FRAMES = N * FRAMES_PER_ITEM;
77	const SHIFT_DURATION = 7;
78	const DROP_DELAY = 1;
79	const DROP_DURATION = 9;
80	const MAX_VISIBLE = 7;
81	const RESULTS_HEIGHT = MAX_VISIBLE * ROW_HEIGHT;
82	const CHARS_PER_FRAME = 1.2;
83	
84	const STEP_EASING = Easing.inOut((t: number) => Easing.cubic(t));
85	
86	const RowContent: React.FC<{
87	  item: { title: string; domain: string; timestamp: string };
88	}> = ({ item }) => (
89	  <>
90	    <div className="truncate font-medium text-foreground text-xs leading-4">
91	      {item.title}
92	    </div>
93	    <div className="mt-1 flex items-center gap-2 text-muted-foreground text-xs leading-4">
94	      <span>{item.domain}</span>
95	      <span className="text-muted-foreground/40">|</span>
96	      <span>{item.timestamp}</span>
97	    </div>
98	  </>
99	);
100	
101	export const IngestedData: React.FC = () => {
102	  const frame = useCurrentFrame();
103	
104	  // ── Typewriter — starts after beam arrives ──
105	  const TYPEWRITER_START = BEAM_TIMING.ARRIVAL + 12;
106	  const typingFrame = Math.max(0, frame - TYPEWRITER_START);
107	  const charsToShow = Math.min(
108	    Math.floor(typingFrame * CHARS_PER_FRAME),
109	    QUERY_TEXT.length
110	  );
111	  const isTypingComplete = charsToShow >= QUERY_TEXT.length;
112	  const typingEndFrame =
113	    TYPEWRITER_START + Math.ceil(QUERY_TEXT.length / CHARS_PER_FRAME);
114	
115	  // Cursor: solid during typing, blinks after, hidden after 30 frames
116	  const cursorFramesAfterTyping = frame - typingEndFrame;
117	  const showCursor =
118	    frame >= TYPEWRITER_START &&
119	    (!isTypingComplete || cursorFramesAfterTyping < 30);
120	  const cursorOpacity =
121	    showCursor && isTypingComplete
122	      ? Math.floor(cursorFramesAfterTyping / 8) % 2 === 0
123	        ? 1
124	        : 0
125	      : showCursor
126	        ? 1
127	        : 0;
128	
129	  // ── Result cycling — starts after typing completes, frozen at loopFrame=0 before ──
130	  // typingEndFrame = 148; window [148, 299] = 152 frames = exactly 1 LOOP_FRAMES cycle
131	  const loopFrame =
132	    frame >= typingEndFrame ? (frame - typingEndFrame) % LOOP_FRAMES : 0;
133	  const stepIndex = Math.floor(loopFrame / FRAMES_PER_ITEM);
134	  const stepFrame = loopFrame % FRAMES_PER_ITEM;
135	
136	  // ── Shift progress (existing items moving down) ──
137	  const shiftProgress = interpolate(stepFrame, [0, SHIFT_DURATION], [0, 1], {
138	    extrapolateLeft: "clamp",
139	    extrapolateRight: "clamp",
140	    easing: STEP_EASING,
141	  });
142	
143	  // ── Drop progress (entering item falling from z=60) ──
144	  const dropProgress = interpolate(
145	    stepFrame - DROP_DELAY,
146	    [0, DROP_DURATION],
147	    [0, 1],
148	    {
149	      extrapolateLeft: "clamp",
150	      extrapolateRight: "clamp",
151	      easing: STEP_EASING,
152	    }
153	  );
154	
155	  // ── 3D drop values for entering item ──
156	  const rowZ = interpolate(dropProgress, [0, 1], [60, 0], {
157	    extrapolateRight: "clamp",
158	  });
159	  const wireframeOpacity = interpolate(
160	    dropProgress,
161	    [0.0, 0.7, 1.0],
162	    [0.8, 0.8, 0],
163	    { extrapolateLeft: "clamp", extrapolateRight: "clamp" }
164	  );
165	  const ghostOpacity = interpolate(
166	    dropProgress,
167	    [0, 0.8, 1.0],
168	    [0.35, 0.35, 0],
169	    { extrapolateLeft: "clamp", extrapolateRight: "clamp" }
170	  );
171	  const landed = wireframeOpacity < 0.01;
172	
173	  // ── Entering item ──
174	  const enteringIdx = stepIndex % N;
175	  const enteringItem = RESULT_ITEMS[enteringIdx]!;
176	
177	  return (
178	    <IsometricCard
179	      animate={false}
180	      entranceFrame={0}
181	      height={512}
182	      width={854}
183	      x={341}
184	      y={1072}
185	    >
186	      <div
187	        className="flex h-full bg-background font-sans"
188	        style={{ transformStyle: "preserve-3d" }}
189	      >
190	        {/* ── Sidebar ── */}
191	        <div
192	          className="flex shrink-0 flex-col border-border border-r"
193	          style={{ width: SIDEBAR_WIDTH }}
194	        >
195	          {/* App name */}
196	          <div className="flex items-center gap-2 border-border border-b px-4 py-3">
197	            <div className="flex size-6 shrink-0 items-center justify-center rounded-full bg-white">
198	              <span className="font-semibold text-black text-xs leading-none">
199	                AC
200	              </span>
201	            </div>
202	            <span className="font-medium text-primary text-sm tracking-tight">
203	              Acme
204	            </span>
205	          </div>
206	
207	          {/* Primary nav */}
208	          <div className="px-2 py-2">
209	            {PRIMARY_NAV.map((item) => (
210	              <div
211	                className={cn(
212	                  "mb-1 rounded-lg px-2 py-2 text-xs",
213	                  item.active
214	                    ? "bg-accent font-medium text-foreground"
215	                    : "font-normal text-muted-foreground"
216	                )}
217	                key={item.label}
218	              >
219	                {item.label}
220	              </div>
221	            ))}
222	          </div>
223	
224	          {/* Manage section */}
225	          <div className="px-2 py-1">
226	            <div className="px-2 py-1 font-medium text-muted-foreground/70 text-xs tracking-wide">
227	              Manage
228	            </div>
229	            {MANAGE_NAV.map((item) => (
230	              <div
231	                className={cn(
232	                  "mb-1 rounded-lg px-2 py-2 text-xs",
233	                  item.active
234	                    ? "bg-accent font-medium text-foreground"
235	                    : "font-normal text-muted-foreground"
236	                )}
237	                key={item.label}
238	              >
239	                {item.label}
240	              </div>
241	            ))}
242	          </div>
243	
244	          {/* Spacer */}
245	          <div className="flex-1" />
246	
247	          {/* Bottom section */}
248	          <div className="border-border border-t px-4 py-3">
249	            <div className="flex items-center gap-2">
250	              <div className="size-5 rounded-full border border-border bg-accent" />
251	              <span className="text-muted-foreground text-xs">Acme Inc</span>
252	            </div>
253	          </div>
254	        </div>
255	
256	        {/* ── Main content ── */}
257	        <div
258	          className="flex flex-1 flex-col"
259	          style={{ transformStyle: "preserve-3d" }}
260	        >
261	          {/* Search query with typewriter */}
262	          <div className="flex min-h-18 flex-col justify-center border-border border-b px-4 py-3">
263	            <div className="text-xs leading-normal">
264	              <span className="font-medium text-primary">lightfast</span>
265	              <span className="text-muted-foreground">.</span>
266	              <span className="text-foreground">search</span>
267	              <span className="text-muted-foreground">(</span>
268	            </div>
269	            <div className="pl-4 text-foreground text-xs leading-normal">
270	              {QUERY_TEXT.slice(0, charsToShow)}
271	              <span
272	                className="font-light text-primary"
273	                style={{ opacity: cursorOpacity }}
274	              >
275	                |
276	              </span>
277	            </div>
278	            <div className="text-xs leading-normal">
279	              <span className="text-muted-foreground">)</span>
280	            </div>
281	          </div>
282	
283	          {/* ── Results list ── */}
284	          <div
285	            className="relative"
286	            style={{
287	              height: RESULTS_HEIGHT,
288	              transformStyle: "preserve-3d",
289	            }}
290	          >
291	            {/* ── Clipped layer: shifting items ── */}
292	            <div className="absolute inset-0 overflow-hidden">
293	              {Array.from({ length: MAX_VISIBLE }, (_, slot) => {
294	                const itemIdx = (((stepIndex - 1 - slot) % N) + N) % N;
295	                const item = RESULT_ITEMS[itemIdx]!;
296	                const fromY = slot * ROW_HEIGHT;
297	                const toY = (slot + 1) * ROW_HEIGHT;
298	                const y = interpolate(shiftProgress, [0, 1], [fromY, toY]);
299	
300	                if (y >= RESULTS_HEIGHT) {
301	                  return null;
302	                }
303	
304	                return (
305	                  <div
306	                    className="absolute right-0 left-0"
307	                    key={itemIdx}
308	                    style={{
309	                      height: ROW_HEIGHT,
310	                      transform: `translateY(${y}px)`,
311	                    }}
312	                  >
313	                    <div className="flex h-full flex-col justify-center border-border border-b px-4 py-2">
314	                      <RowContent item={item} />
315	                    </div>
316	                  </div>
317	                );
318	              })}
319	            </div>
320	
321	            {/* ── 3D layer: entering item with drop effect ── */}
322	            {dropProgress > 0 && (
323	              <div
324	                className="absolute right-0 left-0"
325	                style={{
326	                  height: ROW_HEIGHT,
327	                  transform: "translateY(0px)",
328	                  transformStyle: "preserve-3d",
329	                }}
330	              >
331	                {/* Wireframe: dashed landing zone at z=0 */}
332	                {wireframeOpacity > 0 && (
333	                  <div
334	                    className="pointer-events-none absolute inset-0"
335	                    style={{
336	                      border: "1px dashed var(--muted-foreground)",
337	                      opacity: wireframeOpacity,
338	                    }}
339	                  />
340	                )}
341	
342	                {/* Ghost: faint content preview at landing zone */}
343	                {ghostOpacity > 0 && (
344	                  <div
345	                    className="pointer-events-none absolute inset-0 flex flex-col justify-center px-4 py-2"
346	                    style={{ opacity: ghostOpacity }}
347	                  >
348	                    <RowContent item={enteringItem} />
349	                  </div>
350	                )}
351	
352	                {/* Tracer lines: guide rails from z=0 to z=rowZ */}
353	                {rowZ > 0.5 &&
354	                  wireframeOpacity > 0 &&
355	                  [0, 1].map((side) => (
356	                    <div
357	                      className="pointer-events-none absolute top-0"
358	                      key={`tracer-${side}`}
359	                      style={{
360	                        left: side === 0 ? 0 : undefined,
361	                        right: side === 1 ? 0 : undefined,
362	                        width: 0,
363	                        height: rowZ,
364	                        borderLeft: "1px dashed var(--muted-foreground)",
365	                        transform: "rotateX(90deg)",
366	                        transformOrigin: "0 0",
367	                        opacity: wireframeOpacity,
368	                      }}
369	                    />
370	                  ))}
371	
372	                {/* Floating wrapper at z=rowZ: drops into landing zone */}
373	                <div
374	                  className="absolute inset-0"
375	                  style={{
376	                    transform: `translateZ(${rowZ}px)`,
377	                    transformStyle: "preserve-3d",
378	                  }}
379	                >
380	                  <div
381	                    className={cn(
382	                      "absolute inset-0 flex flex-col justify-center bg-background px-4 py-2",
383	                      landed && "border-border border-b"
384	                    )}
385	                    style={
386	                      landed
387	                        ? undefined
388	                        : {
389	                            border: `1px dashed rgba(128, 128, 128, ${wireframeOpacity})`,
390	                          }
391	                    }
392	                  >
393	                    <RowContent item={enteringItem} />
